vmjc = json.loads(frappe.form_dict.data)
if vmjc and vmjc.get("vmjc_vehicle"):
    if vmjc.get("vmjc_job"):
        filters = [["VM Job Card", "vmjc_vehicle", "=", vmjc.get("vmjc_vehicle")], ["VM Job Card", "vmjc_job", "=", vmjc.get("vmjc_job")], ["VM Job Card", "docstatus", "!=", "2"]]
        fields = ["name", "vmjc_end_date"]
        vmjc_list = frappe.get_all("VM Job Card", fields = fields, filters = filters, page_length = 1, order_by = "vmjc_end_date desc")
        if (vmjc_list and vmjc_list[0].get('name') != vmjc.get('name')):
            frappe.response["last_date"] = vmjc_list[0].get('vmjc_end_date')
            frappe.response["last_vmjc_ref"] = vmjc_list[0].get('name')
    if vmjc.get('vmjc_spare_part'):
        filters = [["VM Job Card", "vmjc_vehicle", "=", vmjc.get("vmjc_vehicle")], ["VM Job Card", "vmjc_spare_part", "=", vmjc.get("vmjc_spare_part")], ["VM Job Card", "docstatus", "!=", "2"]]
        fields = ["name", "vmjc_end_date"]
        vmjc_list = frappe.get_all("VM Job Card", fields = fields, filters = filters, page_length = 1, order_by = "vmjc_end_date desc")
        if (vmjc_list and vmjc_list[0].get('name') != vmjc.get('name')):
            frappe.response["last_part_date"] = vmjc_list[0].get('vmjc_end_date')
            frappe.response["last_part_vmjc_ref"] = vmjc_list[0].get('name')
else:
    frappe.response["message"] = "No Last Service"
